+    /// Returns the first balanced JSON object/array substring beginning at `start` if it can be delimited.
+    private func firstBalancedJSON(in text: String, startingAt start: String.Index) -> String? {
+        let opening = text[start]
+        let closing: Character = opening == "{" ? "}" : "]"
+
+        var depth = 0
+        var inString = false
+        var isEscaping = false
+
+        var index = start
+        while index < text.endIndex {
+            let character = text[index]
+
+            if inString {
+                if isEscaping {
+                    isEscaping = false
+                } else if character == "\\" {
+                    isEscaping = true
+                } else if character == "\"" {
+                    inString = false
+                }
+            } else {
+                if character == "\"" {
+                    inString = true
+                } else if character == opening {
+                    depth += 1
+                } else if character == closing {
+                    depth -= 1
+                    if depth == 0 {
+                        let end = text.index(after: index)
+                        return String(text[start..<end])
+                    }
+                }
+            }
+
+            index = text.index(after: index)
         }
+
+        return nil
+    }
